// server/middleware/authMiddleware.js (Example Express.js JWT authentication middleware)
const jwt = require('jsonwebtoken');
const config = require('../config'); // Assuming config.JWT_SECRET is defined here

const authMiddleware = (req, res, next) => {
  const authHeader = req.headers.authorization;

  // 1. Check if Authorization header exists and is in 'Bearer <token>' format
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    console.warn('AUTH_FAIL: Missing or malformed Authorization header.', { ip: req.ip });
    return res.status(401).json({ message: 'Authentication required: Token missing or malformed.' });
  }

  const token = authHeader.split(' ')[1];

  try {
    // 2. Verify the token using the secret key
    const decoded = jwt.verify(token, config.JWT_SECRET);
    req.user = decoded; // Attach decoded user payload to request for later use
    next(); // Proceed to the next middleware/route handler
  } catch (error) {
    // 3. Handle specific JWT errors
    if (error.name === 'TokenExpiredError') {
      console.warn('AUTH_FAIL: Token expired for user ID (if available):', req.user ? req.user.id : 'N/A', { ip: req.ip });
      return res.status(401).json({ message: 'Authentication failed: Token expired. Please log in again.' });
    } else if (error.name === 'JsonWebTokenError') {
      console.warn('AUTH_FAIL: Invalid token signature/format:', error.message, { ip: req.ip });
      return res.status(401).json({ message: 'Authentication failed: Invalid token. Please log in again.' });
    } else {
      console.error('AUTH_FAIL: Unexpected authentication error:', error.message, { ip: req.ip });
      return res.status(401).json({ message: 'Authentication failed: An unexpected error occurred.' });
    }
  }
};

module.exports = authMiddleware;

