// server/src/middleware/authMiddleware.ts (Example of Express authentication middleware)
import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { env } from '../config/env'; // Assuming env vars are loaded here

interface AuthRequest extends Request {
  user?: { id: string; role: string }; // Define user payload type based on your JWT
}

export const protect = (req: AuthRequest, res: Response, next: NextFunction) => {
  let token;

  if (req.headers.authorization && req.headers.authorization.startsWith('Bearer')) {
    try {
      // Get token from header
      token = req.headers.authorization.split(' ')[1];

      // Verify token
      const decoded = jwt.verify(token, env.JWT_SECRET as string) as { id: string; role: string; iat: number; exp: number };

      // Attach user info to request for subsequent middleware/route handlers
      req.user = { id: decoded.id, role: decoded.role };
      next();
    } catch (error) {
      console.error('Authentication error: Token verification failed.', error);
      return res.status(401).json({ message: 'Not authorized, token failed' });
    }
  }

  if (!token) {
    console.error('Authentication error: No token provided in Authorization header.');
    return res.status(401).json({ message: 'Not authorized, no token' });
  }
};

