// Assuming you have a User model or Drizzle schema for users
const { db } = require('../db/index'); // Assuming your Drizzle client
const { users } = require('../db/schema'); // Assuming users schema
const { eq } = require('drizzle-orm');

exports.protect = async (req, res, next) => {
  let token;

  if (req.headers.authorization && req.headers.authorization.startsWith('Bearer')) {
    token = req.headers.authorization.split(' ')[1];
  }

  // console.log('Incoming Authorization Header:', req.headers.authorization); // Debugging
  // console.log('Extracted Token:', token); // Debugging

  if (!token) {
    return res.status(401).json({ message: 'Not authorized, no token provided' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    // console.log('Decoded Token Payload:', decoded); // Debugging

    // Assuming 'id' is in the JWT payload and corresponds to user ID
    const userResult = await db.select().from(users).where(eq(users.id, decoded.id));
    if (userResult.length === 0) {
      return res.status(401).json({ message: 'Not authorized, user not found' });
    }

    req.user = userResult[0]; // Attach user object to request
    next();
  } catch (error) {
    console.error('Token verification failed:', error.message); // Log actual error
    return res.status(401).json({ message: `Not authorized, token failed: ${error.message}` });
  }
};

